class CpuMuJoCoAnt:
    def time_simulate(self):
        with wp.ScopedDevice("cpu"):
            for _ in range(self.num_frames):
                self.example.step()

    def setup(self):
        with wp.ScopedDevice("cpu"):
            self.example = MuJoCoExample(
                stage_path=None,
                robot="ant",
                randomize=False,
                headless=True,
                actuation="None",
                use_cuda_graph=False,
                world_count=1,
            )

